import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import { Toaster, toast } from 'react-hot-toast';
import { FaUsers, FaClipboardCheck, FaUsersCog, FaSignOutAlt, FaCalendarDay } from 'react-icons/fa';
import Modal from '../components/Modal';
import './SupervisorDashboard.css';

function SupervisorDashboard() {
    const { user, logout } = useAuth();
    const [stats, setStats] = useState({ total_teams: 0, total_workers: 0, today_attendance: 0 });
    const [workers, setWorkers] = useState([]);
    const [teams, setTeams] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('attendance');
    const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
    const [attendanceData, setAttendanceData] = useState({});

    useEffect(() => {
        fetchDashboardData();
    }, []);

    useEffect(() => {
        if (activeTab === 'attendance') {
            fetchAttendanceHistory();
        }
    }, [attendanceDate, activeTab]);

    const fetchDashboardData = async () => {
        try {
            setLoading(true);
            const [statsRes, workersRes, teamsRes] = await Promise.all([
                api.get('/supervisor/stats'),
                api.get('/supervisor/workers'),
                api.get('/supervisor/teams')
            ]);
            setStats(statsRes.data);
            setWorkers(workersRes.data);
            setTeams(teamsRes.data);
        } catch (error) {
            toast.error('Failed to load company data');
        } finally {
            setLoading(false);
        }
    };

    const fetchAttendanceHistory = async () => {
        try {
            const response = await api.get(`/supervisor/attendance-history?date=${attendanceDate}`);
            const mapped = {};
            response.data.forEach(record => {
                mapped[record.worker_id] = { status: record.status, notes: record.notes };
            });
            setAttendanceData(mapped);
        } catch (error) {
            console.error('Attendance fetch error');
        }
    };

    const handleStatusChange = (workerId, status) => {
        setAttendanceData(prev => ({
            ...prev,
            [workerId]: { ...prev[workerId], status }
        }));
    };

    const handleNotesChange = (workerId, notes) => {
        setAttendanceData(prev => ({
            ...prev,
            [workerId]: { ...prev[workerId], notes }
        }));
    };

    const submitAttendance = async () => {
        const payload = {
            date: attendanceDate,
            attendances: Object.keys(attendanceData).map(id => ({
                worker_id: parseInt(id),
                status: attendanceData[id].status,
                notes: attendanceData[id].notes || ''
            })).filter(a => a.status)
        };

        if (payload.attendances.length === 0) {
            toast.error('No attendance marked');
            return;
        }

        try {
            await api.post('/supervisor/attendance', payload);
            toast.success('Attendance submitted successfully');
            fetchDashboardData(); // Refresh stats
        } catch (error) {
            toast.error('Failed to submit attendance');
        }
    };

    const handleLogout = async () => {
        await logout();
        window.location.href = '/login';
    };

    if (loading) return <div className="loading-screen">Loading buildPro Supervisor...</div>;

    return (
        <div className="supervisor-layout">
            <Toaster position="top-right" />

            <aside className="supervisor-sidebar">
                <div className="sidebar-brand">
                    <h2>buildPro</h2>
                    <span>Supervisor Panel</span>
                </div>
                <nav className="sidebar-nav">
                    <button className={activeTab === 'attendance' ? 'active' : ''} onClick={() => setActiveTab('attendance')}>
                        <FaClipboardCheck /> Attendance
                    </button>
                    <button className={activeTab === 'workers' ? 'active' : ''} onClick={() => setActiveTab('workers')}>
                        <FaUsers /> Workers
                    </button>
                    <button className={activeTab === 'teams' ? 'active' : ''} onClick={() => setActiveTab('teams')}>
                        <FaUsersCog /> Teams
                    </button>
                </nav>
                <button className="logout-button" onClick={handleLogout}>
                    <FaSignOutAlt /> Logout
                </button>
            </aside>

            <main className="supervisor-main">
                <header className="main-header">
                    <div className="header-info">
                        <h1>{user?.company?.name || 'Company Dashboard'}</h1>
                        <p>Welcome back, {user?.name}</p>
                    </div>
                    <div className="header-date">
                        <FaCalendarDay />
                        <span>{new Date().toDateString()}</span>
                    </div>
                </header>

                <div className="stats-container">
                    <div className="mini-stat">
                        <h3>{stats.total_workers}</h3>
                        <p>Total Workers</p>
                    </div>
                    <div className="mini-stat">
                        <h3>{stats.total_teams}</h3>
                        <p>Active Teams</p>
                    </div>
                    <div className="mini-stat highlight">
                        <h3>{stats.today_attendance}</h3>
                        <p>Present Today</p>
                    </div>
                </div>

                <div className="content-card">
                    {activeTab === 'attendance' && (
                        <div className="attendance-section">
                            <div className="section-toolbar">
                                <h2>Submit Attendance</h2>
                                <input
                                    type="date"
                                    className="date-input"
                                    value={attendanceDate}
                                    onChange={(e) => setAttendanceDate(e.target.value)}
                                />
                                <button className="save-btn" onClick={submitAttendance}>Save Attendance</button>
                            </div>

                            <div className="attendance-table-wrapper">
                                <table className="attendance-table">
                                    <thead>
                                        <tr>
                                            <th>Worker Name</th>
                                            <th>Team</th>
                                            <th>Status</th>
                                            <th>Notes</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {workers.map(worker => (
                                            <tr key={worker.id}>
                                                <td><strong>{worker.name}</strong></td>
                                                <td><span className="team-tag">{worker.team?.name}</span></td>
                                                <td>
                                                    <div className="status-options">
                                                        <label className={`status-opt ${attendanceData[worker.id]?.status === 'present' ? 'present' : ''}`}>
                                                            <input type="radio" name={`status-${worker.id}`} value="present"
                                                                checked={attendanceData[worker.id]?.status === 'present'}
                                                                onChange={() => handleStatusChange(worker.id, 'present')} /> P
                                                        </label>
                                                        <label className={`status-opt ${attendanceData[worker.id]?.status === 'absent' ? 'absent' : ''}`}>
                                                            <input type="radio" name={`status-${worker.id}`} value="absent"
                                                                checked={attendanceData[worker.id]?.status === 'absent'}
                                                                onChange={() => handleStatusChange(worker.id, 'absent')} /> A
                                                        </label>
                                                        <label className={`status-opt ${attendanceData[worker.id]?.status === 'half_day' ? 'half' : ''}`}>
                                                            <input type="radio" name={`status-${worker.id}`} value="half_day"
                                                                checked={attendanceData[worker.id]?.status === 'half_day'}
                                                                onChange={() => handleStatusChange(worker.id, 'half_day')} /> H
                                                        </label>
                                                    </div>
                                                </td>
                                                <td>
                                                    <input type="text" className="note-input" placeholder="Remark..."
                                                        value={attendanceData[worker.id]?.notes || ''}
                                                        onChange={(e) => handleNotesChange(worker.id, e.target.value)}
                                                    />
                                                </td>
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    )}

                    {activeTab === 'workers' && (
                        <div className="workers-section">
                            <div className="section-toolbar">
                                <h2>Worker Directory</h2>
                            </div>
                            <div className="workers-grid">
                                {workers.map(worker => (
                                    <div className="worker-mini-card" key={worker.id}>
                                        <div className="worker-avatar">{worker.name.charAt(0)}</div>
                                        <div className="worker-info">
                                            <h4>{worker.name}</h4>
                                            <p>{worker.team?.name} • {worker.phone || 'No Phone'}</p>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {activeTab === 'teams' && (
                        <div className="teams-section">
                            <div className="section-toolbar">
                                <h2>Operations Teams</h2>
                            </div>
                            <div className="teams-grid">
                                {teams.map(team => (
                                    <div className="team-mini-card" key={team.id}>
                                        <h4>{team.name}</h4>
                                        <p>{team.workers_count} Members registered</p>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}
                </div>
            </main>
        </div>
    );
}

export default SupervisorDashboard;
